def _is_prime_oracle(x):
    if x < 2:
        return False
    for d in range(2, int(x ** 0.5) + 1):
        if x % d == 0:
            return False
    return True


class Solution:
    def diagonalPrime(self, nums):
        n = len(nums)
        diag_vals = set()
        for i in range(n):
            diag_vals.add(nums[i][i])
            diag_vals.add(nums[i][n - 1 - i])
        primes = [v for v in diag_vals if _is_prime_oracle(v)]
        return max(primes) if primes else 0

