var diagonalPrime = function(nums) {
    function isPrime(x) {
        if (x < 2) return false;
        if (x < 4) return true;
        if (x % 2 === 0) return false;
        for (let i = 3; i * i <= x; i += 2) {
            if (x % i === 0) return false;
        }
        return true;
    }

    const n = nums.length;
    let best = 0;
    for (let i = 0; i < n; i++) {
        const candidates = [nums[i][i], nums[i][n - 1 - i]];
        for (const v of candidates) {
            if (v > best && isPrime(v)) best = v;
        }
    }
    return best;
};
